    /**
     * Solves the color propagation problem on a grid.
     * @param n Number of rows (Long, but practically <= 10^5 for indexing).
     * @param m Number of columns (Long, but practically <= 10^5 for indexing).
     * @param sources Array of source cells: [r, c, color].
     * @return The final state of the grid: Array[Array[Long]].
     */
    def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
        val N = n.toInt
        val M = m.toInt

        // Dist[r][c]: Minimum time (distance) to reach (r, c). Use Long.MaxValue for infinity.
        val infinity: Long = Long.MaxValue
        val dist = Array.ofDim[Long](N, M).map(_ => infinity)

        // FinalColor[r][c]: The maximum color that reached (r, c) at time Dist[r][c].
        val finalColor = Array.ofDim[Long](N, M).map(_ => 0L)

        // Queue for BFS, storing coordinates (r, c)
        val queue = new ArrayDeque[(Int, Int)]()

        // 1. Initialization (Time t=0)
        for (source in sources) {
            val r = source(0).toInt
            val c = source(1).toInt
            val color = source(2)

            // Since multiple sources might share the same initial cell (though problem states they don't, 
            // initializing ensures we take the max color if constraints changed slightly).
            if (color > finalColor(r)(c)) {
                finalColor(r)(c) = color
            }
            dist(r)(c) = 0L
            queue.addLast((r, c))
        }

        val dr = Array(-1, 1, 0, 0) // Up, Down, Left, Right
        val dc = Array(0, 0, -1, 1)

        // 2. BFS Propagation
        while (queue.nonEmpty) {
            val (r, c) = queue.removeFirst()

            val currentTime = dist(r)(c)
            val currentMaxColor = finalColor(r)(c)
            val nextTime = currentTime + 1

            for (i <- 0 until 4) {
                val nr = r + dr(i)
                val nc = c + dc(i)

                // Check boundaries
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {

                    if (nextTime < dist(nr)(nc)) {
                        // Case 1: Found a strictly faster path. Update distance and color, enqueue.
                        dist(nr)(nc) = nextTime
                        finalColor(nr)(nc) = currentMaxColor
                        queue.addLast((nr, nc))

                    } else if (nextTime == dist(nr)(nc)) {
                        // Case 2: Reached at the same minimum time. Update color if the incoming color is greater.
                        if (currentMaxColor > finalColor(nr)(nc)) {
                            finalColor(nr)(nc) = currentMaxColor
                        }
                        // Do not re-enqueue because the time hasn't improved, and all cells at this time level are processed before time + 1.
                    }
                    // Case 3: nextTime > dist(nr)(nc). Ignore, path is too slow.
                }
            }
        }

        // Return the final color grid
        finalColor
    }
